describe("03A-SVG: Types & Themes", () => {
  it("all themes bind semantic CSS tokens with usable stroke and opacity", () => {
    for (const [, theme] of Object.entries(SVG_THEMES)) {
      expect(theme.mode).toBe("css-vars");
